-- Mycelium Breakage Pattern Database
-- Generated: 2026-02-11T01:43:02.738Z
-- Repo: webapp
-- Schema version: 2.0

PRAGMA journal_mode=WAL;

CREATE TABLE IF NOT EXISTS repos (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  total_commits INTEGER DEFAULT 0,
  analyzed_commits INTEGER DEFAULT 0,
  first_date TEXT,
  last_date TEXT,
  mined_at TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS patterns (
  id TEXT PRIMARY KEY,
  repo_id TEXT NOT NULL,
  name TEXT NOT NULL,
  frequency INTEGER NOT NULL,
  category TEXT NOT NULL,
  technology TEXT,
  severity TEXT CHECK(severity IN ('low','medium','high','critical')),
  rule TEXT NOT NULL,
  root_cause TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (repo_id) REFERENCES repos(id)
);

CREATE TABLE IF NOT EXISTS pattern_examples (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  pattern_id TEXT NOT NULL,
  commit_hash TEXT,
  commit_message TEXT,
  commit_date TEXT,
  FOREIGN KEY (pattern_id) REFERENCES patterns(id)
);

CREATE TABLE IF NOT EXISTS hotspots (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  repo_id TEXT NOT NULL,
  file_path TEXT NOT NULL,
  total_changes INTEGER NOT NULL,
  fix_count INTEGER NOT NULL,
  fix_rate REAL NOT NULL,
  risk_level TEXT CHECK(risk_level IN ('low','medium','high','critical')),
  FOREIGN KEY (repo_id) REFERENCES repos(id)
);

CREATE TABLE IF NOT EXISTS coupling (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  repo_id TEXT NOT NULL,
  file_a TEXT NOT NULL,
  file_b TEXT NOT NULL,
  co_change_count INTEGER NOT NULL,
  strength TEXT CHECK(strength IN ('weak','moderate','strong')),
  FOREIGN KEY (repo_id) REFERENCES repos(id)
);

CREATE TABLE IF NOT EXISTS fix_commits (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  repo_id TEXT NOT NULL,
  commit_hash TEXT NOT NULL,
  commit_date TEXT,
  author TEXT,
  message TEXT,
  category TEXT,
  pattern TEXT,
  severity TEXT,
  root_cause TEXT,
  file_count INTEGER,
  confidence REAL,
  FOREIGN KEY (repo_id) REFERENCES repos(id)
);

CREATE TABLE IF NOT EXISTS fix_chains (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  repo_id TEXT NOT NULL,
  break_hash TEXT,
  break_message TEXT,
  fix_hash TEXT,
  fix_message TEXT,
  hours_to_fix REAL,
  FOREIGN KEY (repo_id) REFERENCES repos(id)
);

CREATE INDEX IF NOT EXISTS idx_patterns_category ON patterns(category);
CREATE INDEX IF NOT EXISTS idx_patterns_severity ON patterns(severity);
CREATE INDEX IF NOT EXISTS idx_patterns_frequency ON patterns(frequency DESC);
CREATE INDEX IF NOT EXISTS idx_hotspots_fix_rate ON hotspots(fix_rate DESC);
CREATE INDEX IF NOT EXISTS idx_coupling_count ON coupling(co_change_count DESC);
CREATE INDEX IF NOT EXISTS idx_fix_commits_category ON fix_commits(category);

INSERT OR REPLACE INTO repos VALUES ('webapp', 'webapp', 580, 500, '2026-01-23', '2026-02-11', '2026-02-11T01:43:02.738Z');

INSERT OR REPLACE INTO patterns VALUES ('MCL-WRONG-CSS-VALUE', 'webapp', 'wrong-css-value', 25, 'css-layout', 'html', 'low', 'CSS value changes should be tested at multiple screen sizes. Check for inherited properties and specificity conflicts.', 'Changed height: 120px → 100%. Also: Changed background: linear-gradient(180deg,#ffcc70 0%,#ff9500 30%,#ff6b00 60%,#cc4400 100%) → radial-gradient(ellipse at 20% 20%,rgba(255,107,0,.2) 0%,transparent 50%),radial-gradient(ellipse at 80% 80%,rgba(255,157,77,.15) 0%,transparent 50%); Changed height: 100', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-OVERFLOW-HIDDEN-CLIPS-CHILDREN', 'webapp', 'overflow-hidden-clips-children', 12, 'css-layout', 'html', 'high', 'overflow:hidden on a parent silently clips children that extend beyond bounds. Check all child elements before adding it.', 'Added overflow:hidden — may clip child elements. Also: Changed cards: fill width with 4px gaps, minimum 64px */
