INSERT OR REPLACE INTO patterns VALUES ('MCL-I18N-MISSING-TRANSLATION', 'webapp', 'i18n-missing-translation', 9, 'i18n', 'html', 'medium', 'feat(regression): 12 real regression tests targeting actual breakage patterns — caught and fixed digit-starting i18n key bug in index.html. RULE: Ensure all user-visible strings go through the translation system.', 'feat(regression): 12 real regression tests targeting actual breakage patterns — caught and fixed digit-starting i18n key bug in index.html', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-MISSING-PRECONDITION-CHECK', 'webapp', 'missing-precondition-check', 6, 'null-reference', 'javascript', 'medium', 'Validate prerequisites before executing logic. Check that DOM elements exist, APIs are loaded, and data is present before using them.', 'selfHeal gated at 10 commits, but squash workflow compresses 4-5→1,', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-SCRIPT-ORDER-DEPENDENCY', 'webapp', 'script-order-dependency', 6, 'load-order', 'html', 'high', 'Scripts that call each other''s globals must load in dependency order. Document the dependency chain in a comment.', 'Reordered scripts: 6 removed, 2 added. Also: Added missing return statement — function was returning undefined; Added typeof !== undefined guard — variable was used before definition', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-MISSING-NULL-GUARD', 'webapp', 'missing-null-guard', 6, 'null-reference', 'html', 'medium', 'Check for null/undefined before accessing properties. Common sources: DOM queries returning null, missing API fields, uninitialized state.', 'Added 1 optional chaining operator(s) — null reference fix. Also: Added && guard — was executing without prerequisite check; Modified conditional logic', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-CSS-LAYOUT-ISSUE', 'webapp', 'css-layout-issue', 6, 'css-layout', 'html', 'medium', 'JS errors: add missing helper scripts and resolve currentLang redeclaration. RULE: Test layout at 320px, 768px, 1024px after CSS changes.', 'JS errors: add missing helper scripts and resolve currentLang redeclaration', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-UNHANDLED-EXCEPTION', 'webapp', 'unhandled-exception', 5, 'error-handling', 'html', 'medium', 'Wrap external calls (DOM, fetch, JSON.parse, localStorage) in try-catch. Unhandled exceptions crash the entire function.', 'Wrapped code in try-catch — was crashing on error. Also: Added storage access safety — was crashing on parse error or missing key; Wrapped code in try-catch — was crashing on error', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-MISSING-RETURN-STATEMENT', 'webapp', 'missing-return-statement', 5, 'logic-error', 'html', 'high', 'Functions that compute values must return them. Missing return causes undefined results and silent failures.', 'Added missing return statement — function was returning undefined. Also: Added missing return statement — function was returning undefined; Added missing return statement — function was returning undefined', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-TEST-ISSUE', 'webapp', 'test-issue', 4, 'test-failure', 'config', 'medium', 'make mycelium work on any repo — fix --init crash, strip NumbahWan refs, fix watch.cjs syntax errors, rename .nw-* to .mycelium-*, tested end-to-end o. RULE: Review carefully before committing.', 'make mycelium work on any repo — fix --init crash, strip NumbahWan refs, fix watch.cjs syntax errors, rename .nw-* to .mycelium-*, tested end-to-end on fresh repo', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-MISSING-RESPONSIVE-BREAKPOINT', 'webapp', 'missing-responsive-breakpoint', 4, 'mobile-compat', 'html', 'medium', 'Test every UI change at 320px, 768px, and 1024px. Add @media breakpoints for layouts that break at different screen sizes.', 'Added responsive breakpoint — was broken on different screen sizes. Also: Changed width: min(320px, 80vw) → min(340px, 85vw); Changed height: calc(min(320px, 80vw) * 1.4) → calc(min(340px, 85vw) * 1.4)', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-API-CONTRACT-ISSUE', 'webapp', 'api-contract-issue', 4, 'api-contract', 'html', 'medium', 'card carousel to use cards-v2.json and correct image path. RULE: Validate API response shape before accessing fields.', 'card carousel to use cards-v2.json and correct image path', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-WRONG-ASSET-PATH', 'webapp', 'wrong-asset-path', 3, 'build-config', 'html', 'low', 'Use path constants or import for assets. Hardcoded paths break when files move or builds change output directories.', 'Changed resource path. Also: Changed resource path; Changed resource path', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-USE-BEFORE-DEFINE', 'webapp', 'use-before-define', 3, 'null-reference', 'html', 'high', 'Use typeof check before accessing globals that may not be loaded yet. This often indicates a load-order dependency.', 'Added typeof !== undefined guard — variable was used before definition. Also: Added missing return statement — function was returning undefined; Added || [] fallback — was calling array method on undefined', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-OBJECT-FIT-CROPS-CONTENT', 'webapp', 'object-fit-crops-content', 3, 'css-layout', 'html', 'medium', 'object-fit:cover crops images to fill container. Use contain if the full image must be visible (e.g., card art, logos).', 'Changed object-fit: cover → contain — image was being cropped. Also: Changed width: calc(100% - 16px) → calc(100% - 12px); Changed height: 180px → 200px', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-MISSING-AWAIT', 'webapp', 'missing-await', 3, 'async-timing', 'html', 'high', 'Every async function call that returns data you use must be awaited. Missing await causes race conditions where code uses stale/undefined values.', 'Added missing await — was ignoring promise result. Also: Added missing return statement — function was returning undefined; Added 2 optional chaining operator(s) — null reference fix', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-INNERHTML-DESTROYS-HANDLERS', 'webapp', 'innerhtml-destroys-handlers', 2, 'dom-mutation', 'css', 'high', 'innerHTML = ... destroys all event handlers on child elements. Use textContent for text-only updates, or insertAdjacentHTML/replaceWith to preserve siblings.', 'Replaced innerHTML with textContent — XSS or handler-destruction fix. Also: Added missing return statement — function was returning undefined; Changed font-size: 14px">◆</span><span class="nw-val nwg" id="nwfNwg">0</span></div>'' +
''<div class="nw-item"><span style="font-size:14px">●</span><span clas', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-DEFER-BEFORE-DEPENDENCY', 'webapp', 'defer-before-dependency', 2, 'load-order', 'html', 'high', 'Never use defer on scripts that other scripts depend on at load time. If script B calls script A''s globals, A must load synchronously before B.', 'Removed defer attribute from script tag. Also: Removed overflow:hidden to fix clipping', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-MISSING-TOUCH-SUPPORT', 'webapp', 'missing-touch-support', 2, 'mobile-compat', 'javascript', 'medium', 'Desktop-only event handlers (click, hover) don''t work on mobile. Always test touch interactions and add touch/pointer event handlers.', 'Added touch event handling — broken on mobile. Also: Modified conditional logic; Added touch event handling — broken on mobile', '2026-02-11T01:43:02.738Z');
INSERT OR REPLACE INTO patterns VALUES ('MCL-RACE-CONDITION-NEEDS-DELAY', 'webapp', 'race-condition-needs-delay', 2, 'async-timing', 'html', 'medium', 'If you need setTimeout to fix a bug, you have a race condition. Find the root cause (missing callback, wrong event, load order) instead of papering over it with delays.', 'Added setTimeout(500ms) — timing/race condition fix. Also: Added setTimeout(300ms) — timing/race condition fix; Added string fallback — was showing undefined/null in UI', '2026-02-11T01:43:02.738Z');



